+fn time_operation<F: FnMut()>(mut f: F) -> Vec<u128> {
+    // Warmup
+    for _ in 0..WARMUP_ITERS {
+        f();
+    }
+    // Measure
+    let mut timings = Vec::with_capacity(BENCH_ITERS);
+    for _ in 0..BENCH_ITERS {
+        let start = Instant::now();
+        f();
+        timings.push(start.elapsed().as_nanos());
+    }
+    timings.sort();
+    timings
+}
