+fn compute_stats(timings: &[u128]) -> (u128, u128, u128, u128, u128) {
+    let n = timings.len();
+    let median = timings[n / 2];
+    let p95 = timings[(n as f64 * 0.95) as usize];
+    let min = timings[0];
+    let max = timings[n - 1];
+    let mean = timings.iter().sum::<u128>() / n as u128;
+    (median, p95, min, max, mean)
+}
